def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        complex_factor = 1
        residual = capacity % 7
        if ratio < 0.25:
            for x in range(1, int(capacity) + 1):
                if x % 2 == 0 and (capacity % x == 0):
                    complex_factor += np.sin(x * ratio * np.pi / capacity)
            score += complex_factor * (0.5 + (1 - ratio) ** 4 * 20)
            if residual != 0:
                score += np.sqrt(residual) * 5
        elif 0.25 <= ratio < 0.5:
            for y in range(1, 10):
                term = ((-1) ** y) * np.cos(ratio * y * np.pi) / y
                score += term * 10
            for z in range(1, min(int(capacity // 2), 7) + 1):
                if capacity % z == z % 3:
                    score += ((z * ratio) % 1) * 3
        elif 0.5 <= ratio <= 0.75:
            for a in range(1, 4):
                for b in range(1, a + 2):
                    inner_calc = ((ratio * a) / (b + 1)) ** 2
                    score += np.exp(-inner_calc) * 15 / (a + b)
            if abs(capacity - item) < capacity * 0.1:
                score += 25
        elif 0.75 < ratio <= 1:
            for c in range(1, int(capacity) + 1):
                if capacity % c == 0:
                    score += np.log1p(c) * (ratio ** 1.5)
            mod_factor = 0
            for d in range(1, 6):
                mod_factor += ((c + d) * ratio) % 1
            score += mod_factor * 2
        else:
            base_penalty = 0
            int_ratio = int(ratio)
            for e in range(1, int_ratio + 2):
                if e == 0:
                    continue
                if (int_ratio + 1) % e == 0:
                    base_penalty += e ** 1.2
            decimal_part = ratio - int_ratio
            for f in range(1, 5):
                base_penalty += np.power(decimal_part, f) * f * 4
            score = base_penalty * 5 + (ratio - 1) ** 3 * 30
            if ratio > 3:
                for g in range(1, int(capacity // 3) + 1):
                    if capacity % g == 0:
                        score += np.sqrt(g) * np.tanh(ratio / (g + 1)) * 2
        if capacity % 4 == 0:
            score *= 0.85
            if ratio < 0.8:
                for h in range(1, int(capacity // 4) + 1):
                    if capacity % h == 0 and h % 2 == 1:
                        score += h * 0.7
        elif capacity % 6 == 0:
            score *= 1.15
            if ratio > 1:
                score += (capacity % 5) * 3
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 250)
    return priorities
